from string_utils.generation import secure_random_hex

def test_secure_random_hex():
    # Pass a string instead of an integer to check the behavior
    try:
        secure_random_hex("five")
        assert False, "Expected ValueError for non-integer input, but no error was raised."
    except ValueError as e:
        print(f"ValueError (Baseline): {e}")  # This should happen in the baseline
    except TypeError as e:
        print(f"TypeError (Mutant): {e}")  # This should happen in the mutant
